//                             This was using the filter and not a scripted source before.
// 2.7.101 | 2022-01-04 | raj  | DFCT0010743 - Relate Task is no longer working because button is missing in 2.7.100
// Script Continued Below

(function(query) {
	var _tasker_search = new tasker_search();
	var _tasker_results = _tasker_search.fetchSearchData(query, queryLocation, count, data, facets, $sp);
	return _tasker_results;
})(query);

sp_search_source.facet_generation_script:
(function(query, facetService, searchResults) {
	/* Calculate your facets here using facetService */
	/* var stateFacet = facetService.createFacet('State', 'state'); */
	/* stateFacet.addFacetItem('Facet Item Label', '123'); */

	var _tasker_search = new tasker_search();
	var _tasker_facets = _tasker_search.generateFacets(query, facetService, searchResults);
	return _tasker_facets;
})(query, facetService, searchResults);
